import React, { useState, useEffect } from 'react';
import { ChevronRight } from 'lucide-react';
import { HERO_SLIDES } from '../constants';

const Hero: React.FC = () => {
  const [currentSlide, setCurrentSlide] = useState(0);

  useEffect(() => {
    const timer = setInterval(() => {
      setCurrentSlide((prev) => (prev + 1) % HERO_SLIDES.length);
    }, 5000);
    return () => clearInterval(timer);
  }, []);

  return (
    <section className="relative h-screen w-full overflow-hidden">
      {/* Background Slideshow */}
      {HERO_SLIDES.map((slide, index) => (
        <div
          key={index}
          className={`absolute inset-0 transition-opacity duration-1000 ease-in-out ${index === currentSlide ? 'opacity-100 scale-110' : 'opacity-0 scale-100'}`}
          style={{ transitionProperty: 'opacity, transform' }}
        >
          <img
            src={slide}
            className="w-full h-full object-cover"
            alt={`Slide ${index}`}
          />
          <div className="absolute inset-0 bg-gradient-to-b from-black/60 via-black/20 to-black/80" />
        </div>
      ))}

      {/* Content */}
      <div className="relative z-10 flex flex-col items-center justify-center h-full text-center px-4">
        <div className="max-w-4xl space-y-6">
          <img 
            src="https://grupotsalach.com/wp-content/uploads/2025/07/TSALACH-REAL-ESTATE-1024x194.avif"
            className="w-full max-w-2xl mx-auto drop-shadow-2xl animate-pulse"
            alt="Tsalach Main Branding"
          />

          <div className="w-24 h-px bg-white/50 mx-auto" />

          <h1 className="text-3xl md:text-5xl font-light tracking-tight text-white uppercase leading-tight">
            Tu Puerta de Entrada al <br />
            <span className="font-bold gold-gradient-text">Real Estate Global</span>
          </h1>

          <div className="pt-8">
            <a 
              href="#newsletter"
              className="group inline-flex items-center space-x-3 bg-white/10 hover:bg-white/20 backdrop-blur-md border border-white/20 text-white px-8 py-4 rounded-full transition-all hover:scale-105"
            >
              <span className="font-semibold tracking-widest text-sm">ÚNETE A NUESTRO NEWSLETTER</span>
              <ChevronRight className="group-hover:translate-x-1 transition-transform" />
            </a>
          </div>
        </div>
      </div>
    </section>
  );
};

