import React, { useState, useRef, useEffect } from 'react';
import { MessageSquare, Send, X, Bot, User, Sparkles } from 'lucide-react';
import { GoogleGenAI } from "@google/genai";

const AdvisorChat: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<{role: 'user' | 'bot', text: string}[]>([
    {role: 'bot', text: '¡Hola! Soy tu Asesor AI de Tsalach Real Estate. ¿En qué zona estás buscando invertir hoy? Riviera Maya, Miami o Punta Cana?'}
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  const handleSend = async () => {
    if (!input.trim() || isTyping) return;

    const userMsg = input;
    setMessages(prev => [...prev, {role: 'user', text: userMsg}]);
    setInput('');
    setIsTyping(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Eres un experto asesor inmobiliario de Tsalach Real Estate. Ayuda al cliente con sus dudas sobre inversiones en Riviera Maya, Miami y Punta Cana. Sé profesional, elegante y persuasivo. Usuario dice: ${userMsg}`,
        config: {
            systemInstruction: "Eres un asesor de ventas de lujo para Tsalach Real Estate. Tu tono es sofisticado, experto y servicial."
        }
      });

      setMessages(prev => [...prev, {role: 'bot', text: response.text || 'Lo siento, no pude procesar eso en este momento. Por favor, contáctanos directamente.'}]);
    } catch (err) {
      console.error(err);
      setMessages(prev => [...prev, {role: 'bot', text: 'Hubo un error al conectar con el asesor inteligente. Por favor intenta de nuevo.'}]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="fixed bottom-6 right-6 z-[100]">
      {isOpen ? (
        <div className="bg-zinc-900 border border-white/10 w-[350px] sm:w-[400px] h-[500px] rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in fade-in zoom-in-95">
          <div className="bg-yellow-600 p-4 flex justify-between items-center text-white">
            <div className="flex items-center space-x-2">
              <Bot size={20} />
              <span className="font-bold tracking-wider">Asesor AI Tsalach</span>
            </div>
            <button onClick={() => setIsOpen(false)}><X size={20} /></button>
          </div>

          <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4 scroll-smooth">
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[80%] p-3 rounded-2xl text-sm ${
                  m.role === 'user' 
                  ? 'bg-yellow-600 text-white rounded-br-none' 
                  : 'bg-white/10 text-gray-200 rounded-bl-none border border-white/5'
                }`}>
                  {m.text}
                </div>
              </div>
            ))}
            {isTyping && (
              <div className="flex justify-start">
                <div className="bg-white/5 p-3 rounded-2xl rounded-bl-none border border-white/5 flex space-x-1">
                  <div className="w-1.5 h-1.5 bg-yellow-600 rounded-full animate-bounce" />
                  <div className="w-1.5 h-1.5 bg-yellow-600 rounded-full animate-bounce delay-75" />
                  <div className="w-1.5 h-1.5 bg-yellow-600 rounded-full animate-bounce delay-150" />
                </div>
              </div>
            )}
          </div>

          <div className="p-4 bg-zinc-800/50 border-t border-white/10 flex space-x-2">
            <input 
              type="text" 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
              placeholder="Pregunta por propiedades..."
              className="flex-1 bg-black border border-white/10 rounded-full px-4 py-2 text-sm focus:outline-none focus:border-yellow-600 transition-colors"
            />
            <button 
              onClick={handleSend}
              className="bg-yellow-600 p-2 rounded-full hover:bg-yellow-500 transition-colors"
            >
              <Send size={18} className="text-white" />
            </button>
          </div>
        </div>
      ) : (
        <button 
          onClick={() => setIsOpen(true)}
          className="bg-yellow-600 text-white p-4 rounded-full shadow-2xl hover:scale-110 transition-transform flex items-center space-x-2 border-4 border-black group"
        >
          <Sparkles className="animate-pulse" size={24} />
          <span className="hidden group-hover:inline font-bold uppercase text-xs tracking-widest">Chat Asesor</span>
        </button>
      )}
    </div>
  );
};

export default AdvisorChat;

