import React, { useState, useRef, useEffect } from 'react';
import { Send, X, Bot, Sparkles } from 'lucide-react';
import { GoogleGenAI } from "@google/genai";

const AdvisorChat: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<{role: 'user' | 'bot', text: string}[]>([
    {role: 'bot', text: '¡Hola! Soy tu Asesor AI de Innexus Real Estate. ¿Estás buscando invertir, vivir o establecer tu empresa en Paraguay?'}
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  const handleSend = async () => {
    if (!input.trim() || isTyping) return;

    const userMsg = input;
    setMessages(prev => [...prev, {role: 'user', text: userMsg}]);
    setInput('');
    setIsTyping(true);

    try {
      // En Vite se usa import.meta.env.VITE_API_KEY
      const apiKey = import.meta.env.VITE_API_KEY || process.env.API_KEY;
      const ai = new GoogleGenAI({ apiKey: apiKey });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: userMsg,
        config: {
            systemInstruction: "Eres un experto asesor inmobiliario para Innexus Real Estate en Paraguay. Tu fundadora es Melissa Rojas. Tu enfoque es boutique, estratégico y basado en datos reales. No eres una inmobiliaria de volumen. Ayuda a los clientes a entender las ventajas de invertir en Paraguay (rentabilidad, plusvalía, impuestos bajos, etc). Sé profesional, sofisticado y servicial. Responde siempre en español."
        }
      });

      const text = response.text;
      setMessages(prev => [...prev, {role: 'bot', text: text || 'Para brindarte una mejor atención sobre el mercado paraguayo, te sugiero agendar una llamada directa con Melissa Rojas.'}]);
    } catch (err) {
      console.error(err);
      setMessages(prev => [...prev, {role: 'bot', text: 'Hubo un error al conectar con el asesor inteligente. Por favor intenta de nuevo.'}]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="fixed bottom-6 right-6 z-[100]">
      {isOpen ? (
        <div className="bg-zinc-900 border border-white/10 w-[350px] sm:w-[400px] h-[500px] rounded-3xl shadow-2xl flex flex-col overflow-hidden animate-in fade-in zoom-in-95">
          <div className="bg-yellow-600 p-5 flex justify-between items-center text-white">
            <div className="flex items-center space-x-3">
              <Bot size={22} />
              <div className="flex flex-col">
                <span className="font-bold tracking-wider text-sm">Asesor AI Innexus</span>
                <span className="text-[10px] opacity-80 uppercase tracking-widest">En línea</span>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="hover:rotate-90 transition-transform"><X size={20} /></button>
          </div>

          <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-6 scroll-smooth bg-black/40">
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] p-4 rounded-2xl text-sm leading-relaxed ${
                  m.role === 'user' 
                  ? 'bg-yellow-600 text-white rounded-br-none shadow-xl' 
                  : 'bg-white/10 text-gray-200 rounded-bl-none border border-white/5'
                }`}>
                  {m.text}
                </div>
              </div>
            ))}
            {isTyping && (
              <div className="flex justify-start">
                <div className="bg-white/5 p-4 rounded-2xl rounded-bl-none border border-white/5 flex space-x-1">
                  <div className="w-1.5 h-1.5 bg-yellow-600 rounded-full animate-bounce" />
                  <div className="w-1.5 h-1.5 bg-yellow-600 rounded-full animate-bounce delay-75" />
                  <div className="w-1.5 h-1.5 bg-yellow-600 rounded-full animate-bounce delay-150" />
                </div>
              </div>
            )}
          </div>

          <div className="p-4 bg-zinc-800/80 border-t border-white/5 flex space-x-2">
            <input 
              type="text" 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
              placeholder="Pregunta sobre Paraguay..."
              className="flex-1 bg-black border border-white/10 rounded-2xl px-5 py-4 text-sm focus:outline-none focus:border-yellow-600 transition-colors"
            />
            <button 
              onClick={handleSend}
              className="bg-yellow-600 p-4 rounded-2xl hover:bg-yellow-500 transition-colors shadow-lg"
            >
              <Send size={18} className="text-white" />
            </button>
          </div>
        </div>
      ) : (
        <button 
          onClick={() => setIsOpen(true)}
          className="bg-yellow-600 text-white p-5 rounded-full shadow-2xl hover:scale-110 transition-transform flex items-center space-x-2 border-4 border-black group"
        >
          <Sparkles className="animate-pulse" size={24} />
          <span className="hidden group-hover:inline font-bold uppercase text-xs tracking-widest ml-2">Asesor AI</span>
        </button>
      )}
    </div>
  );
};

export default AdvisorChat;

